let selectedChapters = new Set();
let quizQuestions = [];
let userAnswers = [];
let currentIndex = 0;
const MAX_QUESTIONS = 100;

const chapterNames = Object.keys(QUESTION_BANK);

function totalQuestionsAvailable(chapters){
  return chapters.reduce((sum,c)=> sum + QUESTION_BANK[c].length, 0);
}

const chapterGrid = document.getElementById('chapter-grid');
const fullSyllabusToggle = document.getElementById('full-syllabus-toggle');
const fullSyllabusCount = document.getElementById('full-syllabus-count');
fullSyllabusCount.textContent = totalQuestionsAvailable(chapterNames) + " questions total";

chapterNames.forEach(name=>{
  const div = document.createElement('div');
  div.className = 'chap-option';
  div.dataset.chapter = name;
  div.innerHTML = `<div class="box"></div><div><div class="name">${name}</div><div class="meta">${QUESTION_BANK[name].length} questions available</div></div>`;
  div.addEventListener('click', ()=>{
    fullSyllabusToggle.classList.remove('selected');
    if(selectedChapters.has(name)){
      selectedChapters.delete(name);
      div.classList.remove('selected');
      div.querySelector('.box').textContent='';
    } else {
      selectedChapters.add(name);
      div.classList.add('selected');
      div.querySelector('.box').textContent='OK';
    }
    updateStep1Button();
  });
  chapterGrid.appendChild(div);
});

fullSyllabusToggle.addEventListener('click', ()=>{
  selectedChapters = new Set(chapterNames);
  document.querySelectorAll('.chap-option').forEach(el=>{
    el.classList.add('selected');
    el.querySelector('.box').textContent='OK';
  });
  fullSyllabusToggle.classList.add('selected');
  updateStep1Button();
});

function updateStep1Button(){
  document.getElementById('to-step2').disabled = selectedChapters.size === 0;
}

document.getElementById('to-step2').addEventListener('click', ()=>{
  document.getElementById('screen-chapters').classList.add('hidden');
  document.getElementById('screen-count').classList.remove('hidden');
  setupCountScreen();
});

let selectedCount = 10;

function setupCountScreen(){
  const chapters = Array.from(selectedChapters);
  const available = totalQuestionsAvailable(chapters);
  const maxAllowed = Math.min(MAX_QUESTIONS, available);

  document.getElementById('pool-desc').textContent =
    `You selected ${chapters.length === chapterNames.length ? 'the full syllabus' : chapters.join(', ')} — ${available} questions available in this pool (choose up to ${maxAllowed}).`;

  const slider = document.getElementById('count-slider');
  const num = document.getElementById('count-num');
  slider.max = maxAllowed; num.max = maxAllowed;
  selectedCount = Math.min(10, maxAllowed);
  slider.value = selectedCount; num.value = selectedCount;

  const chipsDiv = document.getElementById('count-chips');
  chipsDiv.innerHTML = '';
  [10,25,50,75,100].filter(n=>n<=maxAllowed).forEach(n=>{
    const chip = document.createElement('div');
    chip.className = 'chip';
    chip.textContent = n + ' Qs';
    chip.addEventListener('click', ()=>{
      selectedCount = n; slider.value = n; num.value = n;
      syncChipSelection();
    });
    chipsDiv.appendChild(chip);
  });
  syncChipSelection();

  slider.oninput = ()=>{ selectedCount = parseInt(slider.value); num.value = selectedCount; syncChipSelection(); };
  num.oninput = ()=>{
    let v = parseInt(num.value)||1;
    v = Math.max(1, Math.min(maxAllowed, v));
    selectedCount = v; slider.value = v;
    syncChipSelection();
  };
}

function syncChipSelection(){
  document.querySelectorAll('.chip').forEach(c=>{
    c.classList.toggle('selected', parseInt(c.textContent)===selectedCount);
  });
}

document.getElementById('back-to-1').addEventListener('click', ()=>{
  document.getElementById('screen-count').classList.add('hidden');
  document.getElementById('screen-chapters').classList.remove('hidden');
});

document.getElementById('to-step3').addEventListener('click', ()=>{
  buildQuiz();
  document.getElementById('screen-count').classList.add('hidden');
  document.getElementById('screen-quiz').classList.remove('hidden');
  renderQuestion();
});

function shuffle(arr){
  const a = arr.slice();
  for(let i=a.length-1;i>0;i--){
    const j = Math.floor(Math.random()*(i+1));
    [a[i],a[j]] = [a[j],a[i]];
  }
  return a;
}

function buildQuiz(){
  const TYPES = ['mcq','mcq-multi','integer','numerical'];
  const RATIO = {mcq:0.30, 'mcq-multi':0.20, integer:0.20, numerical:0.30};

  let poolByType = {mcq:[], 'mcq-multi':[], integer:[], numerical:[]};
  selectedChapters.forEach(c=>{
    QUESTION_BANK[c].forEach(q=> poolByType[q.type].push(Object.assign({}, q, {chapter:c})));
  });
  TYPES.forEach(t=> poolByType[t] = shuffle(poolByType[t]));

  // desired count per type based on target ratio
  let desired = {};
  let sumDesired = 0;
  TYPES.forEach(t=>{ desired[t] = Math.round(selectedCount*RATIO[t]); sumDesired += desired[t]; });
  desired['numerical'] += (selectedCount - sumDesired); // fix rounding drift on the largest bucket

  // guarantee at least 1 of every type present (when count allows and pool has one)
  if(selectedCount >= TYPES.length){
    TYPES.forEach(t=>{
      if(desired[t] === 0 && poolByType[t].length > 0) desired[t] = 1;
    });
    let total = TYPES.reduce((s,t)=>s+desired[t],0);
    desired['numerical'] += (selectedCount - total);
  }

  // cap each type by what's actually available
  let capped = {};
  TYPES.forEach(t=> capped[t] = Math.max(0, Math.min(desired[t], poolByType[t].length)));

  // backfill any shortfall from whichever types still have spare questions
  let totalCapped = TYPES.reduce((s,t)=>s+capped[t],0);
  let deficit = selectedCount - totalCapped;
  if(deficit > 0){
    let order = TYPES.slice().sort((a,b)=> (poolByType[b].length-capped[b]) - (poolByType[a].length-capped[a]));
    for(const t of order){
      if(deficit<=0) break;
      const room = poolByType[t].length - capped[t];
      const take = Math.min(room, deficit);
      capped[t] += take;
      deficit -= take;
    }
  }

  let finalPool = [];
  TYPES.forEach(t=> finalPool = finalPool.concat(poolByType[t].slice(0, capped[t])));
  finalPool = shuffle(finalPool);

  quizQuestions = finalPool.slice(0, selectedCount);
  userAnswers = quizQuestions.map(q => q.type === 'mcq-multi' ? [] : (q.type === 'integer' || q.type === 'numerical' ? '' : null));
  currentIndex = 0;
}

function tagLabel(type){
  if(type==='mcq') return 'MCQ - Single Correct';
  if(type==='mcq-multi') return 'MCQ - One or More Correct';
  if(type==='integer') return 'Integer Type';
  if(type==='numerical') return 'Numerical (up to 2 decimals)';
  return '';
}
function tagClass(type){
  if(type==='integer') return ' integer';
  if(type==='mcq-multi') return ' multi';
  if(type==='numerical') return ' numerical';
  return '';
}

function renderQuestion(){
  const q = quizQuestions[currentIndex];
  const tag = document.getElementById('q-tag');
  tag.textContent = tagLabel(q.type);
  tag.className = 'qtag' + tagClass(q.type);
  document.getElementById('q-progress').textContent = `Question ${currentIndex+1} of ${quizQuestions.length} - ${q.chapter}`;
  document.getElementById('q-text').textContent = q.text;

  const optsDiv = document.getElementById('q-options');
  optsDiv.innerHTML = '';

  if(q.type === 'integer' || q.type === 'numerical'){
    const input = document.createElement('input');
    input.type = 'number';
    input.step = q.type === 'numerical' ? '0.01' : '1';
    input.className = 'int-input';
    input.placeholder = q.type === 'numerical' ? 'Enter your answer, e.g. 3.14' : 'Enter your numeric answer';
    input.value = userAnswers[currentIndex] === '' ? '' : userAnswers[currentIndex];
    input.addEventListener('input', ()=>{ userAnswers[currentIndex] = input.value; });
    optsDiv.appendChild(input);
  } else {
    const letters = ['A','B','C','D'];
    q.options.forEach((opt, i)=>{
      const div = document.createElement('div');
      div.className = 'opt';
      const isPicked = q.type === 'mcq' ? userAnswers[currentIndex] === i : userAnswers[currentIndex].includes(i);
      if(isPicked) div.classList.add('picked');
      div.innerHTML = `<div class="letter">${letters[i]}</div><div>${opt}</div>`;
      div.addEventListener('click', ()=>{
        if(q.type === 'mcq'){
          userAnswers[currentIndex] = i;
        } else {
          const arr = userAnswers[currentIndex];
          const idx = arr.indexOf(i);
          if(idx === -1) arr.push(i); else arr.splice(idx,1);
        }
        renderQuestion();
      });
      optsDiv.appendChild(div);
    });
  }

  document.getElementById('q-prev').style.visibility = currentIndex===0 ? 'hidden':'visible';
  document.getElementById('q-next').textContent = currentIndex === quizQuestions.length-1 ? 'Submit Quiz' : 'Next →';
}

document.getElementById('q-prev').addEventListener('click', ()=>{
  if(currentIndex>0){ currentIndex--; renderQuestion(); }
});
document.getElementById('q-next').addEventListener('click', ()=>{
  if(currentIndex < quizQuestions.length-1){
    currentIndex++;
    renderQuestion();
  } else {
    showResults();
  }
});

function isCorrect(q, userAns){
  if(q.type === 'mcq') return userAns === q.answer;
  if(q.type === 'integer') return Number(userAns) === Number(q.answer);
  if(q.type === 'numerical') return userAns !== '' && Math.abs(Number(userAns) - Number(q.answer)) <= 0.02;
  if(q.type === 'mcq-multi'){
    const a = userAns.slice().sort();
    const b = q.answer.slice().sort();
    return a.length === b.length && a.every((v,i)=> v===b[i]);
  }
  return false;
}

let lastAttempt = { correctCount:0, total:0, items:[] };

function showResults(){
  document.getElementById('screen-quiz').classList.add('hidden');
  document.getElementById('screen-result').classList.remove('hidden');

  let correctCount = 0;
  const letters = ['A','B','C','D'];
  const reviewList = document.getElementById('review-list');
  reviewList.innerHTML = '';
  const items = [];

  quizQuestions.forEach((q, i)=>{
    const ua = userAnswers[i];
    const correct = isCorrect(q, ua);
    if(correct) correctCount++;

    let userAnsText, correctAnsText;
    if(q.type === 'mcq'){
      userAnsText = ua===null ? 'Not answered' : letters[ua]+' - '+q.options[ua];
      correctAnsText = letters[q.answer]+' - '+q.options[q.answer];
    } else if(q.type === 'mcq-multi'){
      userAnsText = ua.length===0 ? 'Not answered' : ua.slice().sort().map(i=>letters[i]).join(', ');
      correctAnsText = q.answer.slice().sort().map(i=>letters[i]).join(', ');
    } else if(q.type === 'numerical'){
      userAnsText = ua === '' ? 'Not answered' : Number(ua).toFixed(2);
      correctAnsText = Number(q.answer).toFixed(2);
    } else {
      userAnsText = ua === '' ? 'Not answered' : ua;
      correctAnsText = q.answer;
    }

    items.push({num:i+1, chapter:q.chapter, type:tagLabel(q.type), text:q.text, correct, userAnsText, correctAnsText, solution:q.solution});

    const item = document.createElement('div');
    item.className = 'review-item';
    item.innerHTML = `
      <div class="review-flag ${correct?'correct':'wrong'}">${correct?'Correct':'Incorrect'} - ${q.chapter}</div>
      <div class="review-q"><b>Q${i+1}.</b> ${q.text}</div>
      <div class="review-answer">Your answer: <b>${userAnsText}</b> &nbsp;|&nbsp; Correct answer: <b>${correctAnsText}</b></div>
      <div class="sol-box"><b>Solution:</b> ${q.solution}</div>
    `;
    reviewList.appendChild(item);
  });

  document.getElementById('score-num').textContent = `${correctCount}/${quizQuestions.length}`;
  lastAttempt = { correctCount, total: quizQuestions.length, items };
}

document.getElementById('retake-btn').addEventListener('click', ()=>{
  document.getElementById('screen-result').classList.add('hidden');
  document.getElementById('screen-chapters').classList.remove('hidden');
  selectedChapters = new Set();
  document.querySelectorAll('.chap-option').forEach(el=>{
    el.classList.remove('selected');
    el.querySelector('.box').textContent='';
  });
  fullSyllabusToggle.classList.remove('selected');
  updateStep1Button();
});

function drawWatermark(doc, pageW, pageH){
  const size = 60;
  for(let y=-20; y<pageH+size; y+=110){
    for(let x=-20; x<pageW+size; x+=130){
      doc.addImage(ICON_WATERMARK_B64, 'PNG', x, y, size, size);
    }
  }
}

function showPdfFallbackLink(blobUrl){
  const row = document.getElementById('pdf-fallback-row');
  const link = document.getElementById('pdf-fallback-link');
  link.href = blobUrl;
  row.classList.remove('hidden');
}

document.getElementById('download-pdf-btn').addEventListener('click', ()=>{
  if(!window.jspdf || !window.jspdf.jsPDF){
    alert('The PDF library did not load (this can happen if your internet connection is slow, or a browser extension/ad-blocker is blocking cdnjs.cloudflare.com). Please refresh the page and try again, or temporarily disable any ad-blocker for this site.');
    return;
  }
  try{
  const jsPDFObj = window.jspdf.jsPDF;
  const doc = new jsPDFObj({unit:'pt', format:'a4'});
  const pageW = doc.internal.pageSize.getWidth();
  const pageH = doc.internal.pageSize.getHeight();
  const margin = 42;
  let y = margin;

  function newPage(){
    doc.addPage();
    drawWatermark(doc, pageW, pageH);
    y = margin;
  }
  function ensureSpace(lines){
    if(y + lines*13 > pageH - margin){ newPage(); }
  }

  drawWatermark(doc, pageW, pageH);

  const logoW = 70, logoH = 70 * (334/400);
  doc.addImage(LOGO_HEADER_B64, 'PNG', margin, margin - 8, logoW, logoH);
  doc.setFont('helvetica','bold'); doc.setFontSize(14); doc.setTextColor(20,20,30);
  doc.text('Physics Quiz Attempt', margin + logoW + 14, margin + 16);
  doc.setFont('helvetica','normal'); doc.setFontSize(10); doc.setTextColor(90,90,110);
  doc.text('Free JEE Advanced preparation - ' + new Date().toLocaleDateString(), margin + logoW + 14, margin + 32);
  y = margin + logoH + 16;

  doc.setFont('helvetica','bold'); doc.setFontSize(14); doc.setTextColor(20,20,30);
  doc.text(`Score: ${lastAttempt.correctCount} / ${lastAttempt.total}`, margin, y); y+=26;

  lastAttempt.items.forEach(item=>{
    ensureSpace(6);
    doc.setFont('helvetica','bold'); doc.setFontSize(10.5);
    doc.setTextColor(item.correct ? 30:180, item.correct ? 140:40, item.correct ? 90:60);
    doc.text(`${item.correct ? 'CORRECT' : 'INCORRECT'}  -  ${item.chapter}  -  ${item.type}`, margin, y); y+=15;

    doc.setFont('helvetica','bold'); doc.setFontSize(11); doc.setTextColor(20,20,30);
    const qLines = doc.splitTextToSize(`Q${item.num}. ${item.text}`, pageW - margin*2);
    ensureSpace(qLines.length);
    doc.text(qLines, margin, y); y += qLines.length*13 + 4;

    doc.setFont('helvetica','normal'); doc.setFontSize(10); doc.setTextColor(90,90,110);
    const ansLine = `Your answer: ${item.userAnsText}   |   Correct answer: ${item.correctAnsText}`;
    const ansLines = doc.splitTextToSize(ansLine, pageW - margin*2);
    ensureSpace(ansLines.length);
    doc.text(ansLines, margin, y); y += ansLines.length*12 + 4;

    doc.setFont('helvetica','italic'); doc.setFontSize(10); doc.setTextColor(60,60,80);
    const solLines = doc.splitTextToSize(`Solution: ${item.solution}`, pageW - margin*2);
    ensureSpace(solLines.length);
    doc.text(solLines, margin, y); y += solLines.length*12 + 18;
  });

  ensureSpace(3);
  doc.setFont('helvetica','normal'); doc.setFontSize(9); doc.setTextColor(120,120,140);
  doc.text('AyuVerse - Where Future Engineers Are Built. Original content, free for personal study use. Not for redistribution or resale.', margin, pageH - 24);

  const pdfBlob = doc.output('blob');
  const blobUrl = URL.createObjectURL(pdfBlob);

  const a = document.createElement('a');
  a.href = blobUrl;
  a.download = 'AyuVerse-Physics-Quiz-Attempt.pdf';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);

  showPdfFallbackLink(blobUrl);
  } catch(err){
    console.error('PDF generation failed:', err);
    alert('Something went wrong while creating the PDF: ' + err.message + '\n\nIf you\'re viewing this inside an app\'s built-in preview (like a chat app\'s file viewer), try opening the page in your regular browser (Chrome/Safari) instead — some in-app previews block downloads entirely.');
  }
});
